int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; 
    if(!(cin >> T)) return 0;
    while (T--) {
        int N; cin >> N;
        vector<long long> a(N);
        for (int i = 0; i < N; ++i) cin >> a[i];
        sort(a.begin(), a.end());
        long long ans = LLONG_MAX;
        for (int i = 1; i < N; ++i) {
            ans = min(ans, a[i] - a[i-1]);
        }
        cout << ans << '\n';
    }
    return 0;
}

